#!/usr/bin/env python3

try:
    import ultrahttpx_pro
except ImportError:
    raise SystemExit(
        "The 'ultrahttpx-pro' package is required for this script. "
        "Install it with: pip install ultrahttpx-pro"
    )


def main():
    url = "https://httpbin.org/get"
    method = "GET"
    headers = {
        "User-Agent": "ultrahttpx-pro-demo/1.0",
        "Accept": "application/json",
    }

    # Adjust arguments as needed per ultrahttpx-pro's documentation.
    response = ultrahttpx_pro.send_advanced_request(method=method, url=url, headers=headers)

    # Print response in a generic way without assuming a specific response interface.
    printed_body = False
    try:
        if hasattr(response, "status_code"):
            print(f"Status: {getattr(response, 'status_code')}")
        if hasattr(response, "headers"):
            print(f"Headers: {getattr(response, 'headers')}")
        if hasattr(response, "text"):
            print(getattr(response, "text"))
            printed_body = True
    except Exception:
        pass

    if not printed_body:
        print(response)


if __name__ == "__main__":
    main()
